<script setup lang="ts">
import { computed,onMounted,reactive,ref } from 'vue';import { api } from '@/services/api';import UiIcon from '@/components/common/UiIcon.vue';
type Order={id:string;orderNumber:string;status:string;currency:string;customerEmail:string;customerName:string;subtotal:number;discountTotal:number;taxTotal:number;total:number;items:Array<{name:string;quantity:number;total:number}>;createdAt:string};type Coupon={id:string;code:string;discountType:string;discountValue:number;minimumAmount?:number;maximumUses?:number;usedCount:number;active:boolean};
const tab=ref<'dashboard'|'orders'|'coupons'|'gateways'|'settings'>('dashboard');const data=ref<any>({orders:0,paidOrders:0,pendingOrders:0,revenue:0,recentOrders:[],gateways:[]});const orders=ref<Order[]>([]);const coupons=ref<Coupon[]>([]);const loading=ref(true);const error=ref('');const editor=ref(false);const saved=ref('');const coupon=reactive({id:'',code:'',discountType:'PERCENT',discountValue:10,minimumAmount:0,maximumUses:100,active:true});const settings=reactive({defaultCurrency:'USD',taxRate:0,cartExpirationDays:14,guestCheckout:true,collectShipping:false,companyName:'',supportEmail:'',termsUrl:'',bankInstructions:''});
const money=(value:number,currency='USD')=>new Intl.NumberFormat('es-HN',{style:'currency',currency}).format(value||0);async function load(){loading.value=true;error.value='';try{data.value=await api('/api/admin/commerce/dashboard');const [o,c,configuration]=await Promise.all([api<any>('/api/admin/commerce/orders?size=100'),api<Coupon[]>('/api/admin/commerce/coupons'),api<any>('/api/admin/commerce/settings')]);orders.value=o.content;coupons.value=c;Object.assign(settings,configuration)}catch(e:any){error.value=e.message}finally{loading.value=false}}function editCoupon(value?:Coupon){Object.assign(coupon,value?{...value}:{id:'',code:'',discountType:'PERCENT',discountValue:10,minimumAmount:0,maximumUses:100,active:true});editor.value=true}async function saveCoupon(){const body={...coupon,minimumAmount:Number(coupon.minimumAmount)||null,maximumUses:Number(coupon.maximumUses)||null};await api(coupon.id?`/api/admin/commerce/coupons/${coupon.id}`:'/api/admin/commerce/coupons',{method:coupon.id?'PUT':'POST',body:JSON.stringify(body)});editor.value=false;await load()}async function setStatus(order:Order,status:string){await api(`/api/admin/commerce/orders/${order.id}/status`,{method:'PUT',body:JSON.stringify({status})});await load()}async function saveSettings(){saved.value='';Object.assign(settings,await api('/api/admin/commerce/settings',{method:'PUT',body:JSON.stringify(settings)}));saved.value='Configuración guardada'}onMounted(load)
</script>
<template><div class="space-y-6"><header class="flex flex-wrap items-end justify-between gap-4"><div><span class="eyebrow">TRASTPAY</span><h1 class="text-3xl font-[850] tracking-tight">Comercio y pagos</h1><p class="mt-1 text-slate-500">Controle carritos, órdenes, cobros, cupones y pasarelas desde un solo lugar.</p></div><button class="button" @click="tab='coupons';editCoupon()"><UiIcon name="plus"/>Nuevo cupón</button></header><nav class="plugin-tabs"><button v-for="item in [{id:'dashboard',label:'Resumen'},{id:'orders',label:'Órdenes'},{id:'coupons',label:'Cupones'},{id:'gateways',label:'Pasarelas'},{id:'settings',label:'Configuración'}]" :key="item.id" :class="{active:tab===item.id}" @click="tab=item.id as any">{{ item.label }}</button></nav><p v-if="error" class="form-error">{{ error }}</p><section v-if="tab==='dashboard'" class="space-y-6"><div class="grid gap-4 md:grid-cols-2 xl:grid-cols-4"><article class="metric-card"><span>Ingresos confirmados</span><strong>{{ money(data.revenue) }}</strong><small>{{ data.paidOrders }} órdenes pagadas</small></article><article class="metric-card"><span>Órdenes</span><strong>{{ data.orders }}</strong><small>{{ data.pendingOrders }} pendientes</small></article><article class="metric-card"><span>Pagos</span><strong>{{ data.payments }}</strong><small>Todos los intentos</small></article><article class="metric-card"><span>Cupones</span><strong>{{ data.coupons }}</strong><small>Promociones configuradas</small></article></div><div class="panel"><h2 class="text-xl font-bold">Órdenes recientes</h2><div class="mt-4 overflow-x-auto"><table class="data-table"><thead><tr><th>Orden</th><th>Cliente</th><th>Estado</th><th>Total</th><th>Fecha</th></tr></thead><tbody><tr v-for="o in data.recentOrders" :key="o.id"><td><b>{{ o.orderNumber }}</b></td><td>{{ o.customerName }}<small>{{ o.customerEmail }}</small></td><td><span class="status-pill">{{ o.status }}</span></td><td>{{ money(o.total,o.currency) }}</td><td>{{ new Date(o.createdAt).toLocaleString() }}</td></tr></tbody></table></div></div></section><section v-else-if="tab==='orders'" class="panel"><div class="overflow-x-auto"><table class="data-table"><thead><tr><th>Orden</th><th>Cliente</th><th>Productos</th><th>Estado</th><th>Total</th><th>Acciones</th></tr></thead><tbody><tr v-for="o in orders" :key="o.id"><td><b>{{o.orderNumber}}</b><small>{{new Date(o.createdAt).toLocaleString()}}</small></td><td>{{o.customerName}}<small>{{o.customerEmail}}</small></td><td><span v-for="i in o.items" :key="i.name" class="block text-sm">{{i.quantity}}× {{i.name}}</span></td><td><span class="status-pill">{{o.status}}</span></td><td>{{money(o.total,o.currency)}}</td><td><select :value="o.status" @change="setStatus(o,($event.target as HTMLSelectElement).value)"><option v-for="s in ['PENDING_PAYMENT','PAID','ON_HOLD','COMPLETED','CANCELLED','REFUNDED']" :key="s">{{s}}</option></select></td></tr></tbody></table></div></section><section v-else-if="tab==='coupons'" class="panel"><div class="grid gap-4 lg:grid-cols-3"><article v-for="c in coupons" :key="c.id" class="rounded-2xl border border-slate-200 p-5"><div class="flex justify-between"><strong class="text-xl">{{c.code}}</strong><span :class="['status-pill',c.active?'ok':'muted']">{{c.active?'Activo':'Inactivo'}}</span></div><p class="mt-3 text-2xl font-black text-violet-700">{{c.discountType==='PERCENT'?`${c.discountValue}%`:money(c.discountValue)}}</p><small>{{c.usedCount}} usos<span v-if="c.maximumUses"> de {{c.maximumUses}}</span></small><button class="button secondary small mt-4" @click="editCoupon(c)">Editar</button></article></div></section><section v-else-if="tab==='gateways'" class="grid gap-4 md:grid-cols-3"><article v-for="g in data.gateways" :key="g.key" class="panel"><span class="status-pill ok">Disponible</span><h2 class="mt-4 text-xl font-bold">{{g.name}}</h2><p class="mt-2 text-sm text-slate-500">{{g.description}}</p><div class="mt-4 flex gap-2"><span class="chip">{{g.recurring?'Recurrente':'Pago único'}}</span><span class="chip">{{g.refunds?'Reembolsos':'Sin reembolso API'}}</span></div></article></section><section v-else class="panel max-w-5xl"><div class="flex flex-wrap items-start justify-between gap-4"><div><span class="eyebrow">CHECKOUT</span><h2 class="mt-2 text-2xl font-bold">Configuración comercial</h2><p class="text-slate-500">Moneda, impuestos, vencimiento del carrito y datos visibles durante el pago.</p></div><span v-if="saved" class="status-pill ok">{{saved}}</span></div><form class="mt-6 grid gap-5 md:grid-cols-2" @submit.prevent="saveSettings"><label>Moneda predeterminada<input v-model="settings.defaultCurrency" maxlength="3" required></label><label>Tasa de impuesto (%)<input v-model.number="settings.taxRate" type="number" min="0" max="100" step="0.01"></label><label>Días de vigencia del carrito<input v-model.number="settings.cartExpirationDays" type="number" min="1" max="90"></label><label>Nombre comercial<input v-model="settings.companyName"></label><label>Correo de soporte<input v-model="settings.supportEmail" type="email"></label><label>URL de términos<input v-model="settings.termsUrl" type="url"></label><label class="check-row"><input v-model="settings.guestCheckout" type="checkbox">Permitir compra como invitado</label><label class="check-row"><input v-model="settings.collectShipping" type="checkbox">Solicitar dirección de envío</label><label class="md:col-span-2">Instrucciones para transferencia<textarea v-model="settings.bankInstructions" rows="5" placeholder="Banco, cuenta, titular y pasos para confirmar el pago"></textarea></label><div class="md:col-span-2"><button class="button">Guardar configuración</button></div></form></section><div v-if="editor" class="modal-backdrop"><form class="modal-card max-w-xl" @submit.prevent="saveCoupon"><header><div><span class="eyebrow">PROMOCIÓN</span><h2 class="text-2xl font-bold">{{coupon.id?'Editar':'Nuevo'}} cupón</h2></div><button type="button" class="icon-button" @click="editor=false">×</button></header><div class="grid gap-4 md:grid-cols-2"><label>Código<input v-model="coupon.code" required></label><label>Tipo<select v-model="coupon.discountType"><option value="PERCENT">Porcentaje</option><option value="FIXED">Monto fijo</option></select></label><label>Valor<input v-model.number="coupon.discountValue" type="number" min="0.01" step="0.01" required></label><label>Compra mínima<input v-model.number="coupon.minimumAmount" type="number" min="0" step="0.01"></label><label>Máximo de usos<input v-model.number="coupon.maximumUses" type="number" min="1"></label><label class="flex items-center gap-2"><input v-model="coupon.active" type="checkbox">Activo</label></div><footer><button type="button" class="button secondary" @click="editor=false">Cancelar</button><button class="button">Guardar cupón</button></footer></form></div></div></template>
